import java.util.*;class P10{static String[] init(){String[] suits={"Hearts","Diamonds","Clubs","Spades"};String[] ranks={"2","3","4","5","6","7","8","9","10","Jack","Queen","King","Ace"};String[] d=new String[52];int k=0;for(String s:suits)for(String r:ranks)d[k++]=r+" of "+s;return d;}static void shuffle(String[] d){int n=d.length;for(int i=0;i<n;i++){int r=i+(int)(Math.random()*(n-i));String t=d[i];d[i]=d[r];d[r]=t;}}public static void main(String[] a){Scanner s=new Scanner(System.in);int n=s.nextInt(),p=s.nextInt();String[] d=init();shuffle(d);if(n%p!=0)return;int k=n/p;int idx=0;for(int i=0;i<p;i++){for(int j=0;j<k;j++)System.out.println("P"+(i+1)+" "+d[idx++]);}}}